    const uint32_t K = Kx;

    // Compute tileK from UB budget: 3 * tileK * 4 bytes
    uint32_t maxTile = UB_BUDGET_BYTES / 12;  // elements
    if (maxTile > HARD_CAP_ELEMS) maxTile = HARD_CAP_ELEMS;
