    KernelMatmulScaleResidualAddClampLogSumExpMishCustom op;
    op.Init(x, weight, bias, scaling, clamp_min, clamp_max, y,
            tilingData.N, tilingData.K, tilingData.M, tilingData.tileK);
    op.Process();
}
